<p>백본 GCN으로는 계산적 단순성과 광범위한 채택으로 인해 LightGCN을 다음과 같이 활용합니다.</p>
<p v-pre class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mtable width="100%"><mtr><mtd width="50%"></mtd><mtd><mrow><msubsup><mover accent="true"><mi>E</mi><mo>ˉ</mo></mover><mi>m</mi><mrow><mo stretchy="false">(</mo><mi>l</mi><mo stretchy="false">)</mo></mrow></msubsup><mo>=</mo><msup><mi>S</mi><mi>m</mi></msup><mo>⋅</mo><msubsup><mover accent="true"><mi>E</mi><mo>ˉ</mo></mover><mi>m</mi><mrow><mo stretchy="false">(</mo><mi>l</mi><mo>−</mo><mn>1</mn><mo stretchy="false">)</mo></mrow></msubsup><mo separator="true">,</mo><mspace width="1em"/><mtext>where </mtext><msubsup><mover accent="true"><mi>E</mi><mo>ˉ</mo></mover><mi>m</mi><mrow><mo stretchy="false">(</mo><mn>0</mn><mo stretchy="false">)</mo></mrow></msubsup><mo>=</mo><msub><mover accent="true"><mi>E</mi><mo>~</mo></mover><mi>m</mi></msub><mtext> and </mtext><msub><mover accent="true"><mi>E</mi><mo>ˉ</mo></mover><mi>m</mi></msub><mo>=</mo><msubsup><mover accent="true"><mi>E</mi><mo>ˉ</mo></mover><mi>m</mi><mrow><mo stretchy="false">(</mo><mi>L</mi><mo stretchy="false">)</mo></mrow></msubsup></mrow></mtd><mtd width="50%"></mtd><mtd><mtext>(5)</mtext></mtd></mtr></mtable><annotation encoding="application/x-tex">\bar{E}^{(l)}_m = S^m \cdot \bar{E}^{(l-1)}_m, \quad \text{where } \bar{E}^{(0)}_m = \tilde{E}_m \text{ and } \bar{E}_m = \bar{E}^{(L)}_m \tag{5}
