<p v-pre class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mtable width="100%"><mtr><mtd width="50%"></mtd><mtd><mrow><msub><mover accent="true"><mi>F</mi><mo>ˉ</mo></mover><mi>M</mi></msub><mo>=</mo><msub><mtext>MeanPool</mtext><mrow><mi>m</mi><mo>∈</mo><mi>M</mi></mrow></msub><mo fence="false" stretchy="true" minsize="1.2em" maxsize="1.2em">(</mo><msubsup><mover accent="true"><mi>F</mi><mo>ˉ</mo></mover><mi>m</mi><mi>s</mi></msubsup><mo separator="true">,</mo><msub><mtext>MeanPool</mtext><mrow><msup><mi>m</mi><mo mathvariant="normal" lspace="0em" rspace="0em">′</mo></msup><mo>∈</mo><mi>M</mi></mrow></msub><mo stretchy="false">(</mo><msubsup><mover accent="true"><mi>F</mi><mo>ˉ</mo></mover><msup><mi>m</mi><mo mathvariant="normal" lspace="0em" rspace="0em">′</mo></msup><mi>g</mi></msubsup><mo stretchy="false">)</mo><mo fence="false" stretchy="true" minsize="1.2em" maxsize="1.2em">)</mo></mrow></mtd><mtd width="50%"></mtd><mtd><mtext>(17)</mtext></mtd></mtr></mtable><annotation encoding="application/x-tex">\bar{F}_M = \text{MeanPool}_{m \in M}\big(\bar{F}^s_m, \text{MeanPool}_{m&#x27; \in M}(\bar{F}^g_{m&#x27;})\big) \tag{17}
